/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Exports the contents of a grid (using the selected order and filters) to an Excel file. LoadWWPContext.Call(&Context)
Do 'OpenDocument'
&CellRow = 1 &FirstColumn = 1
Do 'LoadGridState'
Do 'WriteFilters'
Do 'WriteColumnTitles'
Do 'WriteData'
Do 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Sub 'OpenDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&Random = Random() * 10000 &Filename = !"ExportMonitoraContratoPrevisaoCliente-" + &Random.ToString().Trim() + !".xlsx"
&ExcelDocument.Open(&Filename) Do 'CheckStatus' &ExcelDocument.Clear()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteFilters'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If not (&SerItmCod.IsEmpty() AND &FilterFullText.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Código") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerItmCod WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "WWP_FullTextFilterDescription") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = WWP_Export_SecureText(&FilterFullText) EndIf
If not (&SerItmRecPag.IsEmpty() AND &SerItmSts.IsEmpty() AND &SerItmTip.IsEmpty() AND &SerItmTipPlan.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Lct") If Not &SerItmRecPag.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = &SerItmRecPag.EnumerationDescription() Endif WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "Sts") If Not &SerItmSts.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = &SerItmSts.EnumerationDescription() Endif WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 4, "Tipo") &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = '' do Case Case &SerItmTip.ToString().Trim() = "CONTRATO" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "CONTRATO"
Case &SerItmTip.ToString().Trim() = "PREVISAO" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "PREVISAO"
EndCase WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 6, "Plano") If Not &SerItmTipPlan.IsEmpty() &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = &SerItmTipPlan.EnumerationDescription() Endif EndIf
If not (&SerItmDtaInicio.IsEmpty() AND &SerItmDtaInicio_To.IsEmpty()) WWP_ExportWriteFilter(&ExcelDocument, true, &CellRow, &FirstColumn, "Dta Inicio") &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &SerItmDtaInicio WWP_ExportWriteFilter(&ExcelDocument, false, &CellRow, &FirstColumn + 2, "à") &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &SerItmDtaInicio_To EndIf If &GridState.DynamicFilters.Count >= 1 &GridStateDynamicFilter = &GridState.DynamicFilters.Item(1) &DynamicFiltersSelector1 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector1 = !'SERITMDTAFIM' &SerItmDtaFim1.FromString(&GridStateDynamicFilter.Value) &SerItmDtaFim_To1.FromString(&GridStateDynamicFilter.ValueTo) If not &SerItmDtaFim1.IsEmpty() OR not &SerItmDtaFim_To1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Final" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &SerItmDtaFim1 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &SerItmDtaFim_To1 EndIf Case &DynamicFiltersSelector1 = !'SERITMABV' &SerItmAbv1.FromString(&GridStateDynamicFilter.Value) If not &SerItmAbv1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Abv." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&SerItmAbv1) EndIf Case &DynamicFiltersSelector1 = !'SERITMDIAVCT' &SerItmDiaVct1.FromString(&GridStateDynamicFilter.Value) If not &SerItmDiaVct1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dia Vct. " &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerItmDiaVct1 EndIf Case &DynamicFiltersSelector1 = !'SERCOD' &SerCod1.FromString(&GridStateDynamicFilter.Value) If not &SerCod1.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Plano/Mens." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerCod1 EndIf EndCase If &GridState.DynamicFilters.Count >= 2 &DynamicFiltersEnabled2 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(2) &DynamicFiltersSelector2 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector2 = !'SERITMDTAFIM' &SerItmDtaFim2.FromString(&GridStateDynamicFilter.Value) &SerItmDtaFim_To2.FromString(&GridStateDynamicFilter.ValueTo) If not &SerItmDtaFim2.IsEmpty() OR not &SerItmDtaFim_To2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Final" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &SerItmDtaFim2 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &SerItmDtaFim_To2 EndIf Case &DynamicFiltersSelector2 = !'SERITMABV' &SerItmAbv2.FromString(&GridStateDynamicFilter.Value) If not &SerItmAbv2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Abv." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&SerItmAbv2) EndIf Case &DynamicFiltersSelector2 = !'SERITMDIAVCT' &SerItmDiaVct2.FromString(&GridStateDynamicFilter.Value) If not &SerItmDiaVct2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dia Vct. " &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerItmDiaVct2 EndIf Case &DynamicFiltersSelector2 = !'SERCOD' &SerCod2.FromString(&GridStateDynamicFilter.Value) If not &SerCod2.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Plano/Mens." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerCod2 EndIf EndCase If &GridState.DynamicFilters.Count >= 3 &DynamicFiltersEnabled3 = True &GridStateDynamicFilter = &GridState.DynamicFilters.Item(3) &DynamicFiltersSelector3 = &GridStateDynamicFilter.Selected Do Case Case &DynamicFiltersSelector3 = !'SERITMDTAFIM' &SerItmDtaFim3.FromString(&GridStateDynamicFilter.Value) &SerItmDtaFim_To3.FromString(&GridStateDynamicFilter.ValueTo) If not &SerItmDtaFim3.IsEmpty() OR not &SerItmDtaFim_To3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dta Final" &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Date = &SerItmDtaFim3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "à" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Date = &SerItmDtaFim_To3 EndIf Case &DynamicFiltersSelector3 = !'SERITMABV' &SerItmAbv3.FromString(&GridStateDynamicFilter.Value) If not &SerItmAbv3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Abv." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(&SerItmAbv3) EndIf Case &DynamicFiltersSelector3 = !'SERITMDIAVCT' &SerItmDiaVct3.FromString(&GridStateDynamicFilter.Value) If not &SerItmDiaVct3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Dia Vct. " &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerItmDiaVct3 EndIf Case &DynamicFiltersSelector3 = !'SERCOD' &SerCod3.FromString(&GridStateDynamicFilter.Value) If not &SerCod3.IsEmpty() &CellRow += 1 &ExcelDocument.Cells(&CellRow, &FirstColumn).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn).Color = 3 &ExcelDocument.Cells(&CellRow, &FirstColumn).Text = "Plano/Mens." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Italic = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Number = &SerCod3 EndIf EndCase EndIf EndIf EndIf &CellRow += 2
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteColumnTitles'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Text = "Cód." &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = "Abv" &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = "Tipo" &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = "Plano" &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Text = "Inicio" &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Text = "Final" &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = "Sts." &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = "Cliente" &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Text = "Valor (R$)" &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Text = "Dia Vct." &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Bold = True &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Color = 11 &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Text = "L.Cobranca"
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'WriteData'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
For each order EmpCod (SerItmCod) SerCliRaz when &OrderedBy = 1 order SerItmCod when &OrderedBy = 2 AND &OrderedDsc = False order (SerItmCod) when &OrderedBy = 2 AND &OrderedDsc = True order SerItmAbv when &OrderedBy = 3 AND &OrderedDsc = False order (SerItmAbv) when &OrderedBy = 3 AND &OrderedDsc = True order SerItmTip when &OrderedBy = 4 AND &OrderedDsc = False order (SerItmTip) when &OrderedBy = 4 AND &OrderedDsc = True order SerItmTipPlan when &OrderedBy = 5 AND &OrderedDsc = False order (SerItmTipPlan) when &OrderedBy = 5 AND &OrderedDsc = True order SerItmDtaInicio when &OrderedBy = 6 AND &OrderedDsc = False order (SerItmDtaInicio) when &OrderedBy = 6 AND &OrderedDsc = True order SerItmDtaFim when &OrderedBy = 7 AND &OrderedDsc = False order (SerItmDtaFim) when &OrderedBy = 7 AND &OrderedDsc = True order SerItmSts when &OrderedBy = 8 AND &OrderedDsc = False order (SerItmSts) when &OrderedBy = 8 AND &OrderedDsc = True order SerItmDiaVct when &OrderedBy = 9 AND &OrderedDsc = False order (SerItmDiaVct) when &OrderedBy = 9 AND &OrderedDsc = True order SerItmCbrCod when &OrderedBy = 10 AND &OrderedDsc = False order (SerItmCbrCod) when &OrderedBy = 10 AND &OrderedDsc = True
using DSMonitoraContratoPrevisaoCliente(&SerItmCod, &FilterFullText, &SerItmRecPag, &SerItmSts, &SerItmTip, &SerItmTipPlan , &SerItmDtaInicio, &SerItmDtaInicio_To, &DynamicFiltersSelector1, &SerItmDtaFim1, &SerItmDtaFim_To1, &SerItmAbv1 , &SerItmDiaVct1, &SerCod1, &DynamicFiltersEnabled2, &DynamicFiltersSelector2, &SerItmDtaFim2, &SerItmDtaFim_To2 , &SerItmAbv2, &SerItmDiaVct2, &SerCod2, &DynamicFiltersEnabled3, &DynamicFiltersSelector3, &SerItmDtaFim3 , &SerItmDtaFim_To3, &SerItmAbv3, &SerItmDiaVct3, &SerCod3)
// Write cell values &CellRow += 1
Do 'BeforeWriteLine' &ExcelDocument.Cells(&CellRow, &FirstColumn + 0).Number = SerItmCod &ExcelDocument.Cells(&CellRow, &FirstColumn + 1).Text = WWP_Export_SecureText(SerItmAbv) &ExcelDocument.Cells(&CellRow, &FirstColumn + 2).Text = SerItmTip.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 3).Text = SerItmTipPlan.EnumerationDescription() &ExcelDocument.Cells(&CellRow, &FirstColumn + 4).Date = SerItmDtaInicio &ExcelDocument.Cells(&CellRow, &FirstColumn + 5).Date = SerItmDtaFim &ExcelDocument.Cells(&CellRow, &FirstColumn + 6).Text = SerItmSts.EnumerationDescription() IF SerCliNom.isempty() or SerCliNom.isnull() &SerCliNov = SerCliCodRaz else &SerCliNov = trim(str(SerCliCod)) +' - '+' [' + trim(SerCliNom) + ']' EndIf &ExcelDocument.Cells(&CellRow, &FirstColumn + 7).Text = WWP_Export_SecureText(&SerCliNov) &ExcelDocument.Cells(&CellRow, &FirstColumn + 8).Number = SerItmVlr_Form &ExcelDocument.Cells(&CellRow, &FirstColumn + 9).Number = SerItmDiaVct &ExcelDocument.Cells(&CellRow, &FirstColumn + 10).Number = SerItmCbrCod
Do 'AfterWriteLine'
Endfor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CloseDocument'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
&ExcelDocument.Save() Do 'CheckStatus' &ExcelDocument.Close()
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'CheckStatus'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
If (&ExcelDocument.ErrCode <> 0) &Filename = "" &ErrorMessage = &ExcelDocument.ErrDescription &ExcelDocument.Close() Return EndIf
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'LoadGridState'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
// Load grid state from session. If &Session.Get(!"MonitoraContratoPrevisaoClienteGridState") = !"" &GridState.FromXml(LoadGridState.Udp(!"MonitoraContratoPrevisaoClienteGridState")) Else &GridState.FromXml(&Session.Get(!"MonitoraContratoPrevisaoClienteGridState")) Endif
&OrderedBy = &GridState.OrderedBy &OrderedDsc = &GridState.OrderedDsc
For &GridStateFilterValue in &GridState.FilterValues Do Case Case &GridStateFilterValue.Name = !"SERITMCOD" &SerItmCod.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"FILTERFULLTEXT" &FilterFullText.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"SERITMRECPAG" &SerItmRecPag.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"SERITMSTS" &SerItmSts.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"SERITMTIP" &SerItmTip.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"SERITMTIPPLAN" &SerItmTipPlan.FromString(&GridStateFilterValue.Value) Case &GridStateFilterValue.Name = !"SERITMDTAINICIO" &SerItmDtaInicio.FromString(&GridStateFilterValue.Value) &SerItmDtaInicio_To.FromString(&GridStateFilterValue.ValueTo) EndCase EndFor
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'BeforeWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub
Sub 'AfterWriteLine'
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
EndSub

	/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */

parm(out:&Filename, out:&ErrorMessage);

